+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: Number = 2;
+  minLevel: Number = 2;
+  maxLevel: Number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {level: number, text: string};
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const startIndex = lines.findIndex((line) => /^\\s*<!--\\s*toc\\s*-->\\s*$/i.test(line));
+    if (startIndex === -1) return text;
+
+    let endIndex = -1;
+    for (let index = startIndex + 1; index < lines.length; index++) {
+      if (/^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i.test(lines[index])) {
+        endIndex = index;
+        break;
+      }
+    }
+
+    const regionEnd = endIndex === -1 ? startIndex : endIndex;
+    const headings = this.getHeadings(lines, startIndex, regionEnd, options);
+    const toc = this.createToc(lines[startIndex], headings, options);
+    lines.splice(startIndex, regionEnd - startIndex + 1, ...toc);
+    return lines.join('\
');
+  }
+
+  private getHeadings(lines: string[], startIndex: number, endIndex: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    let inYaml = lines[0]?.trim() === '---';
+    let inFence = false;
+    let fenceCharacter = '';
+    let inMath = false;
+
+    for (let index = 0; index < lines.length; index++) {
+      const line = lines[index];
+      if (inYaml) {
+        if (index > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+        continue;
+      }
+      const fence = line.match(/^\\s*(`{3,}|~{3,})/);
+      if (fence) {
+        const character = fence[1][0];
+        if (!inFence) {
+          inFence = true;
+          fenceCharacter = character;
+        } else if (character === fenceCharacter) {
+          inFence = false;
+        }
+        continue;
+      }
+      if (inFence) continue;
+      if (/^\\s*\\$\\$\\s*$/.test(line)) {
+        inMath = !inMath;
+        continue;
+      }
+      if (inMath || (index >= startIndex && index <= endIndex)) continue;
+
+      const match = line.match(/^ {0,3}(#{1,6})\\s+(.+?)\\s*$/);
+      if (!match) continue;
+      const level = match[1].length;
+      if (level < Number(options.minLevel) || level > Number(options.maxLevel)) continue;
+      const heading = match[2].replace(/\\s+#+\\s*$/, '');
+      if (!this.isExcluded(heading, options.excludeHeadings)) headings.push({level, text: heading});
+    }
+    return headings;
+  }
+
+  private createToc(startMarker: string, headings: Heading[], options: AutoTocOptions): string[] {
+    const anchors = new Map<string, number>();
+    const items = headings.map((heading, index) => {
+      const display = this.displayText(heading.text, options.stripFormattingInToc);
+      let base = options.useExplicitIds ? this.explicitId(heading.text) : '';
+      base = base || this.anchorText(heading.text);
+      const count = anchors.get(base) ?? 0;
+      anchors.set(base, count + 1);
+      const anchor = count === 0 ? base : `${base}-${count}`;
+      const indent = ' '.repeat(Math.max(0, heading.level - Number(options.minLevel)) * Number(options.indentSize));
+      const marker = options.listStyle === 'number' ? (options.orderedListStyle === 'increment' ? `${index + 1}.` : '1.') : options.bulletMarker;
+      return `${indent}${marker} [${display}](#${anchor})`;
+    });
+    const body = options.title ? [options.title, ''] : [];
+    return [startMarker, '', ...body, ...items, '', '<!-- /toc -->', '', ''];
+  }
+
+  private displayText(text: string, stripFormatting: boolean): string {
+    let result = this.resolveLinksAndImages(text).replace(/\\s+#+\\s*$/, '').replace(/\\s*\\{#[^}\\s]+\\}\\s*$/, '');
+    if (stripFormatting) result = this.stripFormatting(result);
+    return result.trim();
+  }
+
+  private anchorText(text: string): string {
+    return this.stripFormatting(this.resolveLinksAndImages(text))
+        .replace(/\\s+#+\\s*$/, '')
+        .replace(/\\s*\\{#[^}\\s]+\\}\\s*$/, '')
+        .toLowerCase()
+        .replace(/\\s+/g, '-')
+        .replace(/[^a-z0-9-_]/g, '')
+        .replace(/-+/g, '-')
+        .replace(/^-+|-+$/g, '');
+  }
+
+  private resolveLinksAndImages(text: string): string {
+    return text
+        .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+        .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+        .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_, target: string, display: string) => display ?? target)
+        .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+  }
+
+  private stripFormatting(text: string): string {
+    return text
+        .replace(/`([^`]*)`/g, '$1')
+        .replace(/(\\*\\*|__)(.*?)\\1/g, '$2')
+        .replace(/(\\*|_)(.*?)\\1/g, '$2')
+        .replace(/~~(.*?)~~/g, '$1')
+        .replace(/<[^>]*>/g, '')
+        .replace(/\\\\([\\\\`*{}_\\[\\]<>#+.!-])/g, '$1');
+  }
+
+  private explicitId(text: string): string {
+    return text.match(/\\s*\\{#([^}\\s]+)\\}\\s*$/)?.[1] ?? '';
+  }
+
+  private isExcluded(heading: string, exclusions: string[]): boolean {
+    const plainHeading = this.displayText(heading, true);
+    return exclusions.some((exclusion) => {
+      if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
+        try {
+          return new RegExp(exclusion.slice(1, -1), 'i').test(plainHeading);
+        } catch (_) {
+          return false;
+        }
+      }
+      return exclusion.toLowerCase() === plainHeading.toLowerCase();
+    });
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [new ExampleBuilder({
